    if n <= 0:
        return False

    def is_prime(num):
        if num < 2:
            return False
        if num == 2:
            return True
        if num % 2 == 0:
            return False
        for i in range(3, int(num**0.5) + 1, 2):
            if num % i == 0:
                return False
        return True

    # Calculate the nth primorial
    primes = []
    candidate = 2
    while len(primes) < n:
        if is_prime(candidate):
            primes.append(candidate)
        candidate += 1

    primorial = 1
    for p in primes:
        primorial *= p

    # Woodall number: n * 2^n - 1
    woodall_number = n * (2 ** n) - 1

