    """
    Check whether the given number is undulating.
    An undulating number is a positive integer with an odd number of digits
    where the digits alternate between two different digits (e.g., 121, 12321, 12121).
    """
    if n <= 0:
        return False

    s = str(n)
    if len(s) < 3:
        return False

    # Check pattern: d1 d2 d1 d2 ...
    d1 = s[0]
    d2 = s[1]
    if d1 == d2:
        return False

    # Ensure length is odd and pattern holds
    if len(s) % 2 == 0:
        return False

    for i in range(1, len(s)):
        if i % 2 == 0:
            if s[i] != d1:
                return False
        else:
            if s[i] != d2:
                return False

    return True
