def next_smallest_palindrome(n: int) -> int:
    if n <= 0:
        return 11
    if n < 10:
        return n + 1

    s = str(n)
    length = len(s)
    half = length // 2
    left_half = s[:half]
    right_half = s[half:] if length % 2 == 0 else s[half+1:]

    # Construct palindrome from left half
    def make_palindrome(left: str) -> int:
        if length % 2 == 0:
            return int(left + left[::-1])
        else:
            return int(left + left[:-1][::-1])

    current_pal = make_palindrome(left_half)

    if current_pal > n:
        return current_pal

    # Try incrementing the left half
    try:
        incremented_left = str(int(left_half) + 1)
        if len(incremented_left) > len(left_half):
            # Overflow case: e.g., 99 -> 100, need to handle differently
            if length == 2:
                return 11
            # For larger numbers, the next palindrome is 10...01
            return int('1' + '0' * (length - 1) + '1')
        new_pal = make_palindrome(incremented_left)
        return new_pal
    except ValueError:
        # Fallback for edge cases
        if length == 2:
            return 11
        return int('1' + '0' * (length - 1) + '1')
