def search(arr):
    if not arr:
        return None

    left, right = 0, len(arr) - 1

    while left < right:
        mid = (left + right) // 2

        # Check if mid is the unique element
        if arr[mid] != arr[mid + 1] and arr[mid] != arr[mid - 1]:
            return arr[mid]

        # Adjust left and right based on the parity of the index
        if mid % 2 == 0:
            # If mid is even, the first half should have even number of elements
            if arr[mid] == arr[mid + 1]:
                left = mid + 2
            else:
                right = mid - 1
        else:
            # If mid is odd, the first half should have even number of elements
            if arr[mid] == arr[mid - 1]:
                left = mid + 1
            else:
                right = mid - 2

    return arr[left]
