def amicable_numbers_sum(limit):
    def sum_divisors(n):
        total = 1
        i = 2
        while i * i <= n:
            if n % i == 0:
                total += i
                if i != n // i:
                    total += n // i
            i += 1
        return total

    amicable_pairs = set()
    for num in range(2, limit + 1):
        d1 = sum_divisors(num)
        if d1 >= limit:
            continue
        d2 = sum_divisors(d1)
        if d2 == num and d1 != num:
            amicable_pairs.add(num)
            amicable_pairs.add(d1)

    return sum(amicable_pairs)
