import math

def find_solution(a, b, n):
    if a == 0 and b == 0:
        return None if n != 0 else (0, 0)
    if a == 0:
        return None if n % b != 0 else (0, n // b)
    if b == 0:
        return None if n % a != 0 else (n // a, 0)

    g = math.gcd(a, b)
    if n % g != 0:
        return None

    a //= g
    b //= g
    n //= g

    # Extended Euclidean Algorithm
    def extended_gcd(a, b):
        if a == 0:
            return b, 0, 1
        gcd, x1, y1 = extended_gcd(b % a, a)
        x = y1 - (b // a) * x1
        y = x1
        return gcd, x, y

    _, x0, y0 = extended_gcd(a, b)

    # General solution: x = x0 + (b/g)*t, y = y0 - (a/g)*t
    # We need to find t such that ax + by = n (already normalized)
    # Since we normalized, a*x0 + b*y0 = 1, so we need to scale by n/g = n'
    # But we already divided n by g, so now a*x0 + b*y0 = 1, and we want = n
    # So multiply x0, y0 by n
    x = x0 * n
    y = y0 * n

    # Reduce to smallest non-negative x if desired, but any solution is fine
    # Let's return the particular solution directly
    return (x, y)
