def get_total_number_of_sequences(m: int, n: int) -> int:
    if n == 0:
        return 1
    if n == 1:
        return m

    # dp[i][x] = number of sequences of length i ending with value x
    # We'll use a dictionary for sparse representation
    dp = {x: 1 for x in range(1, m + 1)}  # sequences of length 1

    for length in range(2, n + 1):
        new_dp = {}
        for prev_val, count in dp.items():
            # Next value must be >= 2 * prev_val and <= m
            start = 2 * prev_val
            if start > m:
                continue
            end = m
            # Sum counts for all valid next values
            # Since we just need the total number of sequences of length 'length',
            # we can accumulate directly without storing per-value counts if we only need the final sum.
            # However, to compute the next layer correctly, we need to know how many sequences end at each value.
            # But notice: for a fixed 'prev_val', the number of valid next values is (m - start + 1).
            # So we can add count * (m - start + 1) to the total for this length? 
            # NO, because the next layer depends on the specific next value, not just the count.
            # So we must iterate.
            for next_val in range(start, end + 1):
                new_dp[next_val] = new_dp.get(next_val, 0) + count
        dp = new_dp
        if not dp:
            return 0

    return sum(dp.values())
