import math

def newman_prime(n: int) -> int:
    """
    Returns the n-th Newman-Shanks-Williams (NSW) prime number.
    NSW numbers are defined by the recurrence:
        NSW(0) = 0
        NSW(1) = 1
        NSW(k) = 2 * NSW(k-1) + NSW(k-2)  for k >= 2

    We generate NSW numbers and check for primality until we find the n-th prime.
    """
    if n <= 0:
        raise ValueError("n must be a positive integer")

    def is_prime(num: int) -> bool:
        if num < 2:
            return False
        if num == 2:
            return True
        if num % 2 == 0:
            return False
        limit = int(math.isqrt(num)) + 1
        for i in range(3, limit, 2):
            if num % i == 0:
                return False
        return True

    a, b = 0, 1  # NSW(0), NSW(1)
    count = 0

    while True:
        if count == n:
            return b

        # Check current NSW number (b)
        if is_prime(b):
            count += 1

        # Generate next NSW number: NSW(k) = 2*NSW(k-1) + NSW(k-2)
        a, b = b, 2 * b + a

# Example test case
