def max_sum_increasing_subseq(arr, n, k, i):
    if i >= len(arr) or k >= len(arr) or i >= k:
        return 0

    # dp[x] will store the maximum sum of an increasing subsequence ending at index x
    dp = [0] * n

    for x in range(n):
        dp[x] = arr[x]  # Minimum sum is the element itself

        for y in range(x):
            if arr[y] < arr[x]:
                dp[x] = max(dp[x], dp[y] + arr[x])

    # Find max sum of increasing subsequence ending at or before index i
    max_before_i = max(dp[:i+1]) if i >= 0 else 0

    # Find max sum of increasing subsequence ending at index k that includes arr[i] as the predecessor
    # We need an increasing subsequence ending at i, then extend to k
    max_ending_at_i = dp[i]

    # Now find max sum ending at k that can extend from some index j <= i where arr[j] < arr[k]
    max_with_k = arr[k]
    for j in range(i + 1, k):
        if arr[j] < arr[k]:
            max_with_k = max(max_with_k, dp[j] + arr[k])

    # If there's a valid increasing path from i to k
    if arr[i] < arr[k]:
        max_with_k = max(max_with_k, max_ending_at_i + arr[k])

    return max(max_before_i, max_with_k)
