    if i < 0 or k >= n or k <= i:
        return 0

    if i == 0:
        if arr[0] < arr[k]:
            return arr[0] + arr[k]
        else:
            return arr[k]

    # dp[j] will store the max sum of increasing subsequence ending at index j considering elements up to index i
    dp = [0] * (i + 1)
    dp[0] = arr[0]

    for j in range(1, i + 1):
