    max_prefix_sum = 0
    for j in range(i + 1):
        if arr[j] < arr[k]:
            max_prefix_sum = max(max_prefix_sum, dp[j])

    if max_prefix_sum == 0:
        return arr[k]

    return max_prefix_sum + arr[k]
