import heapq

def k_smallest_pairs(nums1, nums2, k):
    if not nums1 or not nums2 or k <= 0:
        return []

    min_heap = []

    # Push the first pair from each element in nums1 with index 0 from nums2
    for i in range(len(nums1)):
        if len(min_heap) >= k:
            break
        pair = (nums1[i] + nums2[0], i, 0)
        heapq.heappush(min_heap, pair)

    result = []

    while k > 0 and min_heap:
        _, i, j = heapq.heappop(min_heap)
        result.append([nums1[i], nums2[j]])
        k -= 1

        if j + 1 < len(nums2):
            new_pair = (nums1[i] + nums2[j + 1], i, j + 1)
            heapq.heappush(min_heap, new_pair)

    return result

